import { VerticalCenterContainer } from '@kyokuya-demo/component/container'
import SudokuGame from '@kyokuya/react-game-sudoku'
import type { SudokuBoardCell } from '@kyokuya/react-sudoku'
import { SudokuBoardComponent, useSudokuGameData } from '@kyokuya/react-sudoku'
import Slider from '@material-ui/core/Slider'
import React, { useState } from 'react'
import styled from 'styled-components'

const SUDOKU_SIZE_SQRT = 3
const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT

const SudokuGameDemoContainer = styled(VerticalCenterContainer)`
  margin: 2rem 0;
  background: #f3f3f3;

  @media screen and (max-width: 767px) {
    margin-left: -1rem;
    width: calc(100vw - 2px);
    .game-sudoku {
      width: 100%;
    }
  }
`
export const SudokuGameDemo: React.FC = () => (
  <SudokuGameDemoContainer>
    <SudokuGame />
  </SudokuGameDemoContainer>
)

export const SudokuBoard1: React.FC = () => {
  const data = useSudokuGameData(SUDOKU_SIZE_SQRT, 0, 0)
  const [activatedPuzzleCell, setActivatedPuzzleCell] =
    useState<SudokuBoardCell>({ r: SUDOKU_SIZE >> 1, c: SUDOKU_SIZE >> 1 })

  return (
    <VerticalCenterContainer>
      <SudokuBoardComponent
        childMatrixSize={SUDOKU_SIZE_SQRT}
        segmentNoMap={data.segmentNoMap}
        puzzle={data.solution}
        attempt={data.solution}
        activatedCell={activatedPuzzleCell}
        onCellClick={setActivatedPuzzleCell}
      />
    </VerticalCenterContainer>
  )
}

const SudokuBoard2Container = styled(VerticalCenterContainer)`
  margin: 2rem 0;
`
export const SudokuBoard2: React.FC = () => {
  const [difficulty, setDifficulty] = useState<number>(20)
  const [activatedPuzzleCell, setActivatedPuzzleCell] =
    useState<SudokuBoardCell>({ r: -1, c: -1 })

  const data = useSudokuGameData(SUDOKU_SIZE_SQRT, difficulty / 100, 0)
  return (
    <SudokuBoard2Container>
      <Slider
        value={difficulty}
        step={1}
        min={0}
        max={100}
        valueLabelDisplay="on"
        aria-labelledby="sudoku-difficulty"
        onChange={(e, v) => setDifficulty(v as number)}
        style={{ maxWidth: 400, margin: '8px 0' }}
      />
      <SudokuBoardComponent
        childMatrixSize={SUDOKU_SIZE_SQRT}
        segmentNoMap={data.segmentNoMap}
        puzzle={data.puzzle}
        attempt={data.attempt}
        activatedCell={activatedPuzzleCell}
        onCellClick={setActivatedPuzzleCell}
      />
    </SudokuBoard2Container>
  )
}
